/* tslint:disable no-var-requires */
/* tslint:disable no-console */

import * as React from "react";
import Helmet from "react-helmet";
import { func } from "prop-types";

const config = require("../gatsby-config.js");

interface HtmlProps {
  body: any;
  postBodyComponents: any;
  headComponents: any;
}


export default (props: HtmlProps) => {
  const head = Helmet.rewind();

  const verification = config.siteMetadata && config.siteMetadata.googleVerification ? <meta
    name="google-site-verification"
    content={config.siteMetadata.googleVerification} /> : null;
    
  return (
    <html lang="fr">
      <head>
        {props.headComponents}
        <title>{config.siteMetadata.title}</title>
        <meta httpEquiv="X-UA-Compatible" content="IE=edge" />
        <meta
          name="viewport"
          content="width=device-width, initial-scale=1.0, maximum-scale=1.0"
        />
        <meta charSet="UTF-8" />
        <script src="https://kit.fontawesome.com/677c6a4abf.js" crossOrigin="anonymous"></script>
        {head.title.toComponent()}
        {head.meta.toComponent()}
        {head.link.toComponent()}
        {verification}
      </head>
      <body  >
        <div
          id="___gatsby"
          dangerouslySetInnerHTML={{ __html: props.body }}
        />
        {props.postBodyComponents}
      </body>
    </html>
  );
};
